CREATE VIEW `ads_short_video_log_epis_watch_log_view` (`dt` COMMENT "日期，根据create_time转换而来", `id` COMMENT "自增id", `create_time` COMMENT "服务端", `account_id` COMMENT "账号id", `lang_id` COMMENT "语言", `series_id` COMMENT "剧id", `epis_id` COMMENT "集id", `epis_num` COMMENT "第几集", `ts` COMMENT "app时间戳（客户端）")
COMMENT "海外短剧-观看记录表" AS SELECT `a`.`dt`, `a`.`id`, `a`.`create_time`, `a`.`account_id`, `a`.`lang_id`, `a`.`series_id`, `a`.`epis_id`, `a`.`epis_num`, `a`.`ts`
FROM (SELECT `a`.`dt`, `a`.`id`, `a`.`create_time`, `a`.`account_id`, `a`.`lang_id`, `a`.`series_id`, `a`.`epis_id`, `a`.`epis_num`, `a`.`ts`, row_number() OVER (PARTITION BY `a`.`id` ORDER BY `a`.`create_time` ASC ) AS `rn`
FROM (SELECT `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`dt`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`id`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`create_time`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`account_id`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`lang_id`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`series_id`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`epis_id`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`epis_num`, `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`.`ts`
FROM `ods`.`ods_tidb_short_video_log_ext_epis_watch_log_part2`) `a`) `a`
WHERE `a`.`rn` = 1;